    let posY = f64_add(dsy, view.centerFracY);

    let ix = f64_floor(posX);
    let iy = f64_floor(posY);
    let idx = i32(view.centerTile.x) + f64_to_i32(ix);
    let idy = i32(view.centerTile.y) + f64_to_i32(iy);

    let fx = f64_fract(posX);
    let fy = f64_fract(posY);

    let re = f64_add(f64_from_f32(f32(idx)), fx);
    let im = f64_add(f64_from_f32(f32(idy)), fy);

